[user] Our FastAPI handler returns 422 when the JSON schema drifts.
```python
from fastapi import APIRouter

router = APIRouter()

@router.post("/v2/validate")
def validate_endpoint(payload: dict) -> dict:
    schema = payload.get("schema") or "v1"
    return {"endpoint": "/v2/validate", "json": True, "schema": schema}
